<?php require_once __DIR__.'/config/auth.php'; require_once __DIR__.'/components.php';$username=trim($_GET['username']??'');$us=db()->prepare('SELECT id,username FROM users WHERE username=? LIMIT 1');$us->bind_param('s',$username);$us->execute();$profile=$us->get_result()->fetch_assoc();require_once __DIR__.'/header.php';if(!$profile)echo '<div class="panel empty"><h3>User not found</h3></div>';else{echo '<section class="panel" style="padding:24px;margin-bottom:18px"><h2 style="margin:0 0 6px">@'.e($profile['username']).' on Link-Locker</h2><p class="muted" style="margin:0">Public items only.</p></section>';$stmt=db()->prepare('SELECT * FROM cards WHERE user_id=? AND visibility="Public" ORDER BY created_at DESC');$stmt->bind_param('i',$profile['id']);$stmt->execute();$cards=$stmt->get_result()->fetch_all(MYSQLI_ASSOC);if(!$cards)echo '<div class="panel empty"><h3>No public items yet</h3></div>';else{echo '<div class="grid">';foreach($cards as $c)render_card($c,false);echo '</div>';}}require_once __DIR__.'/footer.php'; ?>